-- ============================================================================
-- Quiz Seed: Luke — Part 3 (Chapters 13–18)
-- 3 difficulties × 6 chapters = 96 total questions
--   kids:   3 per chapter  = 18
--   teens:  5 per chapter  = 30
--   adults: 8 per chapter  = 48
-- ============================================================================

-- ═══════════════ CHAPTERS 13–15 ═══════════════

-- ═══ Luke Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 13, 'kids', 1, 'What did Jesus say would happen to people who do not repent?', 'They shall all likewise perish — Jesus warned everyone to turn from sin', 'Nothing bad will happen to them', 'They will become very rich', 'They will live forever without God', 'a', 'Luke 13:3 — "I tell you, Nay: but, except ye repent, ye shall all likewise perish."'),
('Luke', 13, 'kids', 2, 'What did Jesus compare the kingdom of God to?', 'A mustard seed that grows into a great tree where birds nest in the branches', 'A big castle with gold walls', 'A deep ocean full of fish', 'A tall mountain covered with snow', 'a', 'Luke 13:19 — "It is like a grain of mustard seed, which a man took, and cast into his garden; and it grew, and waxed a great tree; and the fowls of the air lodged in the branches of it."'),
('Luke', 13, 'kids', 3, 'What did Jesus do for the woman who had been bent over for eighteen years?', 'He healed her and she stood up straight and praised God', 'He told her to wait until tomorrow', 'He asked the Pharisees to help her', 'He gave her medicine', 'a', 'Luke 13:12-13 — "And when Jesus saw her, he called her to him, and said unto her, Woman, thou art loosed from thine infirmity. And he laid his hands on her: and immediately she was made straight, and glorified God."'),
-- Teens
('Luke', 13, 'teens', 1, 'What did the ruler of the synagogue complain about when Jesus healed on the Sabbath?', 'He said there are six days to work and people should come to be healed on those days, not the Sabbath', 'He was happy that Jesus healed the woman', 'He asked Jesus to heal more people', 'He invited Jesus to come back next Sabbath', 'a', 'Luke 13:14 — "And the ruler of the synagogue answered with indignation, because that Jesus had healed on the sabbath day, and said unto the people, There are six days in which men ought to work: in them therefore come and be healed, and not on the sabbath day."'),
('Luke', 13, 'teens', 2, 'What did Jesus call the religious leaders who opposed Sabbath healing?', 'Hypocrites — because they would untie their ox or donkey on the Sabbath to give it water, but objected to freeing a daughter of Abraham from Satan''s bondage', 'Faithful followers of the law', 'Wise teachers of Israel', 'True servants of God', 'a', 'Luke 13:15 — "Thou hypocrite, doth not each one of you on the sabbath loose his ox or his ass from the stall, and lead him away to watering?"'),
('Luke', 13, 'teens', 3, 'What did Jesus say about the gate that leads to salvation?', 'Strive to enter in at the strait gate: for many will seek to enter in, and shall not be able', 'The gate is wide and everyone can fit through', 'There is no gate at all', 'Only Jews can enter the gate', 'a', 'Luke 13:24 — "Strive to enter in at the strait gate: for many, I say unto you, will seek to enter in, and shall not be able."'),
('Luke', 13, 'teens', 4, 'What reversal did Jesus predict about who would be in the kingdom?', 'There are last which shall be first, and there are first which shall be last — Gentiles will come from east, west, north, and south while some expected members will be excluded', 'The wealthy will always be first', 'No reversal will ever happen', 'Only the first will remain first', 'a', 'Luke 13:29-30 — "And they shall come from the east, and from the west, and from the north, and from the south, and shall sit down in the kingdom of God. And, behold, there are last which shall be first, and there are first which shall be last."'),
('Luke', 13, 'teens', 5, 'What did Jesus lament about Jerusalem?', 'O Jerusalem, Jerusalem, which killest the prophets — how often would I have gathered thy children together as a hen doth gather her brood under her wings, and ye would not', 'Jerusalem is the greatest city in the world', 'Jerusalem always welcomes God''s prophets', 'Jerusalem needs better walls and defences', 'a', 'Luke 13:34 — "O Jerusalem, Jerusalem, which killest the prophets, and stonest them that are sent unto thee; how often would I have gathered thy children together, as a hen doth gather her brood under her wings, and ye would not!"'),
-- Adults
('Luke', 13, 'adults', 1, 'What theological error does Jesus correct when asked about the Galileans whose blood Pilate mingled with their sacrifices?', 'He rejects the assumption that suffering indicates greater sinfulness — those who suffered were not worse sinners than others, but all must repent or face a similar fate. Tragedy is a call to repentance, not a basis for judgment of others', 'Those who suffer are always being punished for sin', 'Only innocent people suffer', 'Suffering has no spiritual significance', 'a', 'Luke 13:2-3 — "Suppose ye that these Galilaeans were sinners above all the Galilaeans, because they suffered such things? I tell you, Nay: but, except ye repent, ye shall all likewise perish." Jesus refutes retributive theology while urging universal repentance.'),
('Luke', 13, 'adults', 2, 'What does the parable of the barren fig tree teach about God''s patience and judgment?', 'God grants a season of grace (the extra year of digging and dunging) but patience has a limit — the tree that fails to bear fruit after extended opportunity will ultimately be cut down. Mercy delays judgment but does not cancel it', 'God will wait forever with no consequences', 'The fig tree represents the temple only', 'Judgment is never coming', 'a', 'Luke 13:6-9 — "Lord, let it alone this year also, till I shall dig about it, and dung it: And if it bear fruit, well: and if not, then after that thou shalt cut it down." The vinedresser (Christ) intercedes for more time, but fruitlessness will ultimately bring judgment.'),
('Luke', 13, 'adults', 3, 'What does Jesus'' healing of the woman bent over for eighteen years reveal about the Sabbath''s purpose?', 'The Sabbath was made for the liberation and blessing of God''s people — Jesus calls her a "daughter of Abraham, whom Satan hath bound," reframing healing as release from bondage, which perfectly fulfils the Sabbath''s redemptive intent', 'The Sabbath prohibits all activity', 'Healing violates the Sabbath law', 'Only emergencies justify Sabbath work', 'a', 'Luke 13:16 — "And ought not this woman, being a daughter of Abraham, whom Satan hath bound, lo, these eighteen years, be loosed from this bond on the sabbath day?" Jesus frames Sabbath healing as Sabbath liberation — the very purpose of the day.'),
('Luke', 13, 'adults', 4, 'What does the parable of the mustard seed teach about the kingdom''s growth pattern?', 'The kingdom begins insignificantly (like the smallest seed) but grows to surprising magnitude (a great tree) — God''s kingdom starts with a small band of disciples but will grow to encompass people from all nations', 'The kingdom will always remain small', 'Only large movements matter to God', 'The kingdom grows through military conquest', 'a', 'Luke 13:18-19 — "Unto what is the kingdom of God like?... It is like a grain of mustard seed... and it grew, and waxed a great tree." The contrast between the tiny seed and the great tree mirrors the contrast between Jesus'' small following and the future worldwide church.'),
('Luke', 13, 'adults', 5, 'What does "Lord, Lord, open unto us" and the response "I know you not whence ye are" teach about false assurance?', 'Superficial association with Jesus (eating in His presence, hearing Him teach) is insufficient — genuine relationship requires entering through the narrow gate of repentance and obedience, not presuming on proximity', 'Simply being near Jesus guarantees salvation', 'Everyone who calls on the Lord will be saved regardless', 'Knowledge of Jesus'' teaching is enough', 'a', 'Luke 13:25-27 — "Lord, Lord, open unto us... I know you not whence ye are; depart from me, all ye workers of iniquity." These people had proximity to Jesus but not genuine relationship. Acquaintance is not the same as discipleship.'),
('Luke', 13, 'adults', 6, 'What does Jesus'' response to the warning about Herod — "Go ye, and tell that fox" — reveal?', 'Jesus shows fearless defiance of political threats — calling Herod a fox (cunning but insignificant compared to God''s purposes), and declaring that His ministry timeline is determined by divine necessity, not human threats', 'Jesus was afraid of Herod', 'Jesus planned to flee from Herod', 'Jesus wanted to make peace with Herod', 'a', 'Luke 13:32 — "Go ye, and tell that fox, Behold, I cast out devils, and I do cures to day and to morrow, and the third day I shall be perfected." Jesus asserts sovereign control over His own schedule, implying He will die in Jerusalem on God''s timetable, not Herod''s.'),
('Luke', 13, 'adults', 7, 'What does the lament over Jerusalem reveal about divine sovereignty and human responsibility?', 'Jesus wept because He desired to gather Jerusalem''s children but they would not — showing genuine divine desire for their salvation alongside their responsible rejection. Both God''s will to save and human will to refuse are affirmed', 'God does not care about Jerusalem', 'The people had no choice in the matter', 'Jerusalem was always obedient', 'a', 'Luke 13:34 — "How often would I have gathered thy children together... and ye would not!" The tension between "I would" and "ye would not" holds together divine compassion and human culpability without resolving the mystery.'),
('Luke', 13, 'adults', 8, 'What does "your house is left unto you desolate" prophetically anticipate?', 'The destruction of the temple in AD 70 — because Israel rejected the Messiah, the temple (their "house") would be abandoned by God''s presence, leading to its physical destruction by the Romans', 'A minor renovation of the temple', 'The temple would last forever', 'The house refers to a private home', 'a', 'Luke 13:35 — "Behold, your house is left unto you desolate." This echoes Jeremiah 22:5 and anticipates the temple''s destruction. "Your house" shifts from "my house" (Luke 2:49) — God''s departure precedes physical destruction.');

-- ═══ Luke Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 14, 'kids', 1, 'What did Jesus say about choosing the best seat at a dinner?', 'Sit in the lowest place so the host can invite you higher — those who humble themselves will be lifted up', 'Always grab the best seat first', 'Fight for the seat closest to the host', 'It does not matter where you sit', 'a', 'Luke 14:10-11 — "Go and sit down in the lowest room; that when he that bade thee cometh, he may say unto thee, Friend, go up higher... For whosoever exalteth himself shall be abased; and he that humbleth himself shall be exalted."'),
('Luke', 14, 'kids', 2, 'In the parable of the great supper, what excuses did the invited guests make?', 'One bought a field, one bought oxen, and one had just gotten married — they all missed the feast', 'They were all too sick to come', 'They came early and ate everything', 'They brought better food to share', 'a', 'Luke 14:18-20 — The three excuses — buying land, buying oxen, and a new marriage — represent worldly priorities that crowd out God''s invitation.'),
('Luke', 14, 'kids', 3, 'Who did the master invite to the feast after the first guests refused?', 'The poor, the maimed, the halt, and the blind from the streets and lanes', 'Only rich and powerful people', 'Only his family members', 'Only people from other countries', 'a', 'Luke 14:21 — "Go out quickly into the streets and lanes of the city, and bring in hither the poor, and the maimed, and the halt, and the blind."'),
-- Teens
('Luke', 14, 'teens', 1, 'What principle did Jesus teach about being exalted and humbled?', 'Whosoever exalteth himself shall be abased; and he that humbleth himself shall be exalted', 'The proud always succeed', 'Humility is weakness', 'Only strong people are exalted', 'a', 'Luke 14:11 — "For whosoever exalteth himself shall be abased; and he that humbleth himself shall be exalted."'),
('Luke', 14, 'teens', 2, 'Who did Jesus say you should invite when you host a feast?', 'The poor, the maimed, the lame, the blind — those who cannot repay you, and you shall be recompensed at the resurrection of the just', 'Only your friends and rich neighbours', 'People who can repay you with bigger feasts', 'Only important community leaders', 'a', 'Luke 14:13-14 — "But when thou makest a feast, call the poor, the maimed, the lame, the blind: And thou shalt be blessed; for they cannot recompense thee: for thou shalt be recompensed at the resurrection of the just."'),
('Luke', 14, 'teens', 3, 'What did Jesus say about counting the cost before following Him?', 'Like a man building a tower who first counts the cost to see if he can finish, or a king going to war who considers if he can win — discipleship requires counting the cost', 'Just follow without thinking', 'The cost is always zero', 'Only rich people need to count the cost', 'a', 'Luke 14:28-31 — "For which of you, intending to build a tower, sitteth not down first, and counteth the cost, whether he have sufficient to finish it?"'),
('Luke', 14, 'teens', 4, 'What shocking statement did Jesus make about family relationships and discipleship?', 'If any man come to me, and hate not his father, and mother, and wife, and children, and brethren, and sisters, yea, and his own life also, he cannot be my disciple', 'You must always put family before Jesus', 'Family is more important than anything', 'Jesus never asked anyone to leave their family', 'a', 'Luke 14:26 — "If any man come to me, and hate not his father, and mother, and wife, and children, and brethren, and sisters, yea, and his own life also, he cannot be my disciple." "Hate" is a Semitic idiom meaning "love less by comparison."'),
('Luke', 14, 'teens', 5, 'What did Jesus say about salt that has lost its flavour?', 'It is neither fit for the land nor for the dunghill — men cast it out. Salt without saltiness is useless', 'It can easily regain its flavour', 'It becomes sweeter', 'It is still useful for cooking', 'a', 'Luke 14:34-35 — "Salt is good: but if the salt have lost his savour, wherewith shall it be seasoned? It is neither fit for the land, nor yet for the dunghill; but men cast it out."'),
-- Adults
('Luke', 14, 'adults', 1, 'What does the parable of the great supper teach about Israel''s rejection and the inclusion of outsiders?', 'The originally invited guests (Israel''s religious elite) refuse the invitation through worldly excuses, so the master sends servants to bring in the marginalized (poor, maimed, blind) and then Gentiles from highways and hedges — the kingdom is filled with unexpected guests', 'All the invited guests attended happily', 'Only the original guests could come', 'The feast was cancelled', 'a', 'Luke 14:16-24 — The two rounds of invitation (streets/lanes of the city, then highways/hedges) likely represent outreach first to marginalized Jews, then to Gentiles. "None of those men which were bidden shall taste of my supper" is a solemn warning.'),
('Luke', 14, 'adults', 2, 'How does "hate" in verse 26 function as a Semitic idiom, and what does it actually demand?', 'In Hebrew idiom, "hate" means "love less" by comparison — it demands supreme loyalty to Jesus above every human relationship, not literal hatred of family. Genesis 29:31 uses the same idiom: Leah was "hated" (loved less) compared to Rachel', 'Jesus commands literal hatred of all family', 'Family should be completely abandoned', 'This verse only applies to monks and nuns', 'a', 'Luke 14:26 — Compare Matthew 10:37 which clarifies: "He that loveth father or mother more than me is not worthy of me." The Semitic comparative idiom places Christ''s claim as absolute, surpassing all other loyalties.'),
('Luke', 14, 'adults', 3, 'What do the twin parables of the tower builder and the warring king teach about discipleship?', 'Both parables urge sober assessment before committing — discipleship is not a casual decision but a total life commitment that should be entered with eyes wide open about its demands, lest one start but fail to finish', 'Jesus was teaching architecture and military strategy', 'These parables discourage people from following Jesus', 'Only wealthy people can be disciples', 'a', 'Luke 14:28-33 — The tower builder who cannot finish faces ridicule; the king who cannot win must negotiate peace. Both analogies warn against superficial commitment and lead to verse 33: "Whosoever he be of you that forsaketh not all that he hath, he cannot be my disciple."'),
('Luke', 14, 'adults', 4, 'What is the literary function of the three excuses in the great supper parable?', 'They represent legitimate worldly concerns (property, business, family) that become sinful when they take priority over God''s invitation — the excuses escalate in intensity (field, oxen, marriage) and all begin with "I" (self-centred refusal)', 'The excuses were all completely valid', 'Only one excuse was unreasonable', 'The host should have chosen a better date', 'a', 'Luke 14:18-20 — Each excuse involves a good thing (land, livelihood, marriage) elevated above the ultimate good. Deuteronomy 20:5-7 lists similar exemptions from war — what excuses a soldier from battle does not excuse one from God''s banquet.'),
('Luke', 14, 'adults', 5, 'What does "compel them to come in" mean in the context of the parable?', 'The urgency and earnestness of the gospel invitation — the master wants his house filled and insists that even those from the highways and hedges (the most unlikely guests) be persuaded to come. It speaks to God''s passionate desire that none miss His grace', 'Physical force should be used in evangelism', 'People should be forced to become Christians', 'Only certain people are worthy of invitation', 'a', 'Luke 14:23 — "Go out into the highways and hedges, and compel them to come in, that my house may be filled." The "compulsion" is persuasive urgency (cf. 2 Corinthians 5:11, "we persuade men"), not physical coercion.'),
('Luke', 14, 'adults', 6, 'What does Jesus'' silence of the Pharisees regarding Sabbath healing of the man with dropsy demonstrate?', 'The Pharisees could not answer Jesus'' question "Is it lawful to heal on the sabbath day?" because any answer would undermine their position — their silence reveals the indefensibility of opposing mercy on the Sabbath', 'The Pharisees agreed with Jesus', 'The Pharisees simply did not hear the question', 'Jesus avoided confrontation with the Pharisees', 'a', 'Luke 14:3-6 — "Is it lawful to heal on the sabbath day? And they held their peace... Which of you shall have an ass or an ox fallen into a pit, and will not straightway pull him out on the sabbath day? And they could not answer him again to these things."'),
('Luke', 14, 'adults', 7, 'What does the instruction to invite the poor rather than the rich to your feast teach about the kingdom''s economy?', 'The kingdom operates on grace, not reciprocity — inviting those who cannot repay mirrors God''s own generosity toward undeserving sinners and will be rewarded "at the resurrection of the just," shifting the reward timeline from earthly to eternal', 'Only poor people should eat together', 'Hospitality to friends is wrong', 'This teaching has no practical application', 'a', 'Luke 14:12-14 — Jesus disrupts the honour-shame patronage system of ancient culture, where banquets were investments in social capital. Kingdom hospitality serves without expectation, trusting God for the return.'),
('Luke', 14, 'adults', 8, 'What does the salt metaphor at the end of chapter 14 warn disciples about?', 'Disciples who lose their distinctive commitment become useless to the kingdom — just as salt without savour serves no purpose (not even as fertilizer), half-hearted discipleship benefits neither God nor the world', 'Salt is only for cooking', 'This warning applies only to the twelve apostles', 'Salt never actually loses its flavour', 'a', 'Luke 14:34-35 — "Salt is good: but if the salt have lost his savour, wherewith shall it be seasoned?" In context, following the cost-of-discipleship teaching, salt represents wholehearted commitment. Compromise renders a disciple worthless.');

-- ═══ Luke Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 15, 'kids', 1, 'In the parable of the lost sheep, what did the shepherd do when one sheep was lost?', 'He left the ninety-nine and went after the one lost sheep until he found it', 'He forgot about the lost sheep', 'He sent someone else to look for it', 'He counted the ninety-nine and was satisfied', 'a', 'Luke 15:4 — "What man of you, having an hundred sheep, if he lose one of them, doth not leave the ninety and nine in the wilderness, and go after that which is lost, until he find it?"'),
('Luke', 15, 'kids', 2, 'In the story of the prodigal son, what happened to the young man after he spent all his money?', 'He was so hungry he wanted to eat the pigs'' food', 'He found a better job in the far country', 'He became rich again quickly', 'He went straight home', 'a', 'Luke 15:15-16 — "And he went and joined himself to a citizen of that country; and he sent him into his fields to feed swine. And he would fain have filled his belly with the husks that the swine did eat: and no man gave unto him."'),
('Luke', 15, 'kids', 3, 'What did the father do when he saw his lost son coming home?', 'He ran to him, hugged him, and kissed him', 'He turned him away at the door', 'He made him wait outside', 'He sent a servant to talk to him', 'a', 'Luke 15:20 — "But when he was yet a great way off, his father saw him, and had compassion, and ran, and fell on his neck, and kissed him."'),
-- Teens
('Luke', 15, 'teens', 1, 'What happens in heaven when one sinner repents?', 'There is joy in heaven over one sinner that repenteth, more than over ninety and nine just persons which need no repentance', 'Nothing special happens', 'Only the angels notice', 'Heaven waits until many sinners repent at once', 'a', 'Luke 15:7 — "I say unto you, that likewise joy shall be in heaven over one sinner that repenteth, more than over ninety and nine just persons, which need no repentance."'),
('Luke', 15, 'teens', 2, 'What did the prodigal son plan to say to his father?', 'Father, I have sinned against heaven, and before thee, and am no more worthy to be called thy son: make me as one of thy hired servants', 'Father, give me more money', 'Father, I did nothing wrong', 'Father, my brother caused all my problems', 'a', 'Luke 15:18-19 — "I will arise and go to my father, and will say unto him, Father, I have sinned against heaven, and before thee, And am no more worthy to be called thy son: make me as one of thy hired servants."'),
('Luke', 15, 'teens', 3, 'What did the father give the returning prodigal son?', 'The best robe, a ring for his hand, shoes for his feet, and a fatted calf for a feast', 'A list of rules he must follow', 'A small room in the servants'' quarters', 'Nothing until he proved himself', 'a', 'Luke 15:22-23 — "Bring forth the best robe, and put it on him; and put a ring on his hand, and shoes on his feet: And bring hither the fatted calf, and kill it; and let us eat, and be merry."'),
('Luke', 15, 'teens', 4, 'Why was the older brother angry?', 'He was upset that his father threw a feast for the returning prodigal while he had faithfully served for years and never received even a young goat', 'He was happy his brother returned', 'He was angry about the weather', 'He was upset about his own work', 'a', 'Luke 15:28-30 — "And he was angry, and would not go in... Lo, these many years do I serve thee, neither transgressed I at any time thy commandment: and yet thou never gavest me a kid, that I might make merry with my friends."'),
('Luke', 15, 'teens', 5, 'What did the father say about the prodigal''s return?', 'This my son was dead, and is alive again; he was lost, and is found', 'My son must earn back my trust first', 'My son deserves punishment before forgiveness', 'My son should have stayed away longer', 'a', 'Luke 15:24 — "For this my son was dead, and is alive again; he was lost, and is found. And they began to be merry."'),
-- Adults
('Luke', 15, 'adults', 1, 'What is the narrative context that prompted Jesus to tell the three parables of Luke 15?', 'The Pharisees and scribes murmured because Jesus received sinners and ate with them — the three parables are Jesus'' defence of His ministry to the lost, revealing God''s heart for the outcast', 'Jesus was teaching in the temple', 'The disciples asked for a parable', 'A crowd demanded entertainment', 'a', 'Luke 15:1-2 — "Then drew near unto him all the publicans and sinners for to hear him. And the Pharisees and scribes murmured, saying, This man receiveth sinners, and eateth with them." All three parables respond to this criticism.'),
('Luke', 15, 'adults', 2, 'How do the three parables (lost sheep, lost coin, lost son) form a literary progression?', 'They escalate in value and intimacy: from one of a hundred sheep to one of ten coins to one of two sons — the ratio of lost to found increases, the searching becomes more personal, and the final parable adds the dimension of free will (the son chose to leave)', 'They all tell the same story', 'Each parable contradicts the previous one', 'They decrease in importance', 'a', 'Luke 15:4,8,11 — The progression moves from animal (sheep) to object (coin) to person (son), from 1/100 to 1/10 to 1/2, and from wandering (sheep) to being lost passively (coin) to deliberate departure (son).'),
('Luke', 15, 'adults', 3, 'What does the father running to meet the prodigal son reveal about God?', 'In ancient Near Eastern culture, a dignified patriarch would never run — the father''s running displays undignified, extravagant grace that absorbs the shame the son deserved. It pictures God''s eagerness to restore repentant sinners', 'The father was exercising for health', 'Running was normal for wealthy men', 'The father was angry and rushing to punish', 'a', 'Luke 15:20 — "When he was yet a great way off, his father saw him, and had compassion, and ran." Kenneth Bailey notes that a Middle Eastern patriarch running would hike up his robes, exposing his legs — a culturally humiliating act done out of love.'),
('Luke', 15, 'adults', 4, 'What do the robe, ring, and shoes symbolise in the prodigal''s restoration?', 'The best robe signifies honour and full sonship; the ring represents authority and family identity; shoes distinguish a son from a slave (who went barefoot) — full restoration, not servanthood, is the father''s gift', 'They were simply practical gifts', 'They meant the son would become a servant', 'They were given reluctantly', 'a', 'Luke 15:22 — "The best robe" (honour), "ring" (signet ring = authority), "shoes" (free son, not barefoot slave). The father does not even let the son finish his rehearsed speech before restoring him completely.'),
('Luke', 15, 'adults', 5, 'Who does the elder brother represent in the parable, and what is his problem?', 'He represents the Pharisees and scribes — those who serve God dutifully but resent His grace toward sinners. His problem is a works-based mentality that sees obedience as earning merit rather than flowing from love', 'He represents the Roman government', 'He represents the Gentile nations', 'He represents the prodigal''s friends', 'a', 'Luke 15:29 — "Lo, these many years do I serve thee, neither transgressed I at any time thy commandment." The elder brother''s language reveals a servant mentality, not a son''s heart. He never says "my brother" but "thy son" (v.30), distancing himself.'),
('Luke', 15, 'adults', 6, 'What does the father''s response "Son, thou art ever with me, and all that I have is thine" correct about the elder brother''s complaint?', 'The elder brother already had everything — his complaint reveals he never appreciated what he had. He served out of duty, not love, and failed to understand that the father''s generosity to the prodigal did not diminish his own inheritance', 'The father was dismissing the elder brother', 'The elder brother lost his inheritance', 'The father chose the prodigal over the elder', 'a', 'Luke 15:31 — "Son, thou art ever with me, and all that I have is thine." The father gently corrects: the elder son''s inheritance was never threatened. His resentment reveals he viewed his relationship as transactional rather than filial.'),
('Luke', 15, 'adults', 7, 'What does the prodigal''s statement "I have sinned against heaven, and before thee" reveal about the nature of sin?', 'All sin is ultimately vertical (against God/"heaven") before it is horizontal (against others) — echoing David''s confession in Psalm 51:4, "Against thee, thee only, have I sinned." The prodigal recognises that his rebellion was first and foremost against God', 'Sin only affects other people', 'Sin is a private matter with no consequences', 'Heaven has nothing to do with sin', 'a', 'Luke 15:18 — "I have sinned against heaven, and before thee." The order is significant: heaven first, then the earthly father. This shows genuine repentance recognises the God-ward dimension of all sin (cf. Psalm 51:4).'),
('Luke', 15, 'adults', 8, 'Why does the parable leave the elder brother''s response unresolved?', 'The open ending is deliberate — Jesus leaves the Pharisees (whom the elder brother represents) to decide whether they will join the feast or remain outside in resentful self-righteousness. It is an invitation, not a condemnation', 'Luke forgot to finish the parable', 'The elder brother''s response is obvious', 'The parable was actually complete', 'a', 'Luke 15:32 — The father pleads with the elder son but we never learn if he enters. This open ending mirrors Jesus'' real-time appeal to the Pharisees: Will you join the celebration of God''s grace toward sinners, or will you remain outside?');

-- ═══════════════ CHAPTERS 16–18 ═══════════════

-- ═══ Luke Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 16, 'kids', 1, 'What did Jesus say about serving two masters?', 'No servant can serve two masters — you cannot serve God and money', 'You can serve as many masters as you want', 'Money is the most important thing', 'God wants you to focus on getting rich', 'a', 'Luke 16:13 — "No servant can serve two masters: for either he will hate the one, and love the other; or else he will hold to the one, and despise the other. Ye cannot serve God and mammon."'),
('Luke', 16, 'kids', 2, 'In the story of the rich man and Lazarus, who lay at the rich man''s gate?', 'A poor beggar named Lazarus who was full of sores', 'A wealthy merchant', 'A Roman soldier', 'A priest from the temple', 'a', 'Luke 16:20 — "And there was a certain beggar named Lazarus, which was laid at his gate, full of sores."'),
('Luke', 16, 'kids', 3, 'What happened to Lazarus when he died?', 'He was carried by the angels into Abraham''s bosom — a place of comfort and rest', 'He went to a place of suffering', 'He became an angel', 'Nothing happened to him', 'a', 'Luke 16:22 — "And it came to pass, that the beggar died, and was carried by the angels into Abraham''s bosom."'),
-- Teens
('Luke', 16, 'teens', 1, 'What lesson did Jesus draw from the parable of the unjust steward?', 'He that is faithful in that which is least is faithful also in much — use worldly resources wisely to make friends for eternity', 'Cheating is always acceptable', 'Dishonesty is a virtue', 'Money does not matter at all', 'a', 'Luke 16:10 — "He that is faithful in that which is least is faithful also in much: and he that is unjust in the least is unjust also in much."'),
('Luke', 16, 'teens', 2, 'What did Jesus say about what men highly esteem?', 'That which is highly esteemed amongst men is abomination in the sight of God', 'Whatever men value is also valued by God', 'God and men always agree', 'Human standards are always correct', 'a', 'Luke 16:15 — "Ye are they which justify yourselves before men; but God knoweth your hearts: for that which is highly esteemed amongst men is abomination in the sight of God."'),
('Luke', 16, 'teens', 3, 'What did the rich man in torment ask Abraham to do?', 'Send Lazarus to dip his finger in water and cool his tongue, for he was tormented in the flame', 'Let him return to earth as a rich man', 'Give him a second chance at life', 'Send food from Abraham''s table', 'a', 'Luke 16:24 — "And he cried and said, Father Abraham, have mercy on me, and send Lazarus, that he may dip the tip of his finger in water, and cool my tongue; for I am tormented in this flame."'),
('Luke', 16, 'teens', 4, 'What reason did Abraham give for not sending Lazarus to warn the rich man''s brothers?', 'They have Moses and the prophets; let them hear them — if they will not believe Scripture, they will not be persuaded even if one rose from the dead', 'Abraham said he would send Lazarus', 'Abraham had no way to communicate with earth', 'The brothers already knew the truth', 'a', 'Luke 16:29,31 — "They have Moses and the prophets; let them hear them... If they hear not Moses and the prophets, neither will they be persuaded, though one rose from the dead."'),
('Luke', 16, 'teens', 5, 'What did Abraham say about the great gulf between heaven and hell?', 'There is a great gulf fixed between the place of comfort and the place of torment, so that none can cross from one side to the other', 'People can freely cross back and forth', 'The gulf will eventually disappear', 'Only angels can cross the gulf', 'a', 'Luke 16:26 — "And beside all this, between us and you there is a great gulf fixed: so that they which would pass from hence to you cannot; neither can they pass to us, that would come from thence."'),
-- Adults
('Luke', 16, 'adults', 1, 'What is Jesus commending in the parable of the unjust steward — dishonesty or shrewdness?', 'The lord commended the steward''s shrewdness (prudent use of present resources for future security), not his dishonesty — Jesus says the children of this world are wiser in their generation than the children of light. Believers should be equally strategic with eternal investments', 'Jesus is endorsing dishonesty', 'Stealing is acceptable for Christians', 'The parable has no moral lesson', 'a', 'Luke 16:8 — "The lord commended the unjust steward, because he had done wisely: for the children of this world are in their generation wiser than the children of light." The commendation is for foresight and decisive action, not for dishonesty.'),
('Luke', 16, 'adults', 2, 'What does "make to yourselves friends of the mammon of unrighteousness" mean?', 'Use worldly wealth strategically for eternal purposes — invest in people and God''s kingdom so that when earthly resources fail, those blessed by your generosity will welcome you into everlasting habitations', 'Become friends with wealthy sinners', 'Money is evil and should be destroyed', 'Bribery is acceptable in God''s kingdom', 'a', 'Luke 16:9 — "Make to yourselves friends of the mammon of unrighteousness; that, when ye fail, they may receive you into everlasting habitations." The paradox is that unrighteous mammon can serve righteous ends through wise, generous stewardship.'),
('Luke', 16, 'adults', 3, 'Is the Rich Man and Lazarus a parable or a historical account, and what is its primary teaching?', 'Whether parable or historical account, its primary teaching is that eternal destinies are fixed at death, earthly wealth provides no advantage in the afterlife, and Scripture (Moses and the prophets) is sufficient for salvation — miracles will not convince those who reject God''s word', 'It is purely fictional with no lessons', 'It teaches that all rich people go to hell', 'It only applies to first-century Jews', 'a', 'Luke 16:19-31 — The account is unique in using a proper name (Lazarus). Its teachings — reversal of earthly fortunes, the finality of death, the sufficiency of Scripture — are its theological core regardless of genre classification.'),
('Luke', 16, 'adults', 4, 'What does the "great gulf fixed" between Abraham''s bosom and Hades teach about the afterlife?', 'After death, destinies are permanent and irreversible — there is no crossing from torment to comfort or vice versa, ruling out post-mortem repentance, soul sleep, or second chances', 'The gulf is temporary and will dissolve', 'People can pray their way across', 'The afterlife is the same for everyone', 'a', 'Luke 16:26 — "Between us and you there is a great gulf fixed." The permanence of the gulf teaches the irreversibility of eternal destinies, urging repentance in this life as the only window of opportunity.'),
('Luke', 16, 'adults', 5, 'What prophetic irony exists in Abraham''s statement "neither will they be persuaded, though one rose from the dead"?', 'This anticipates Jesus'' own resurrection — even after Christ rose from the dead, many who rejected Scripture still refused to believe, proving Abraham''s point that miracles cannot overcome wilful rejection of God''s word', 'Abraham was wrong about this prediction', 'Everyone believed after Jesus rose', 'The resurrection convinced all the Pharisees', 'a', 'Luke 16:31 — The dramatic irony is overwhelming: Jesus (a man named in connection with Lazarus imagery) will rise from the dead, yet the religious leaders will still not believe. Scripture rejected cannot be replaced by miracles.'),
('Luke', 16, 'adults', 6, 'What does "the law and the prophets were until John" mean about salvation history?', 'The era of the Law and Prophets culminated in John the Baptist, and since then the kingdom of God is preached — marking a turning point in redemptive history from the old covenant era to the new kingdom proclamation', 'The Old Testament is now irrelevant', 'John the Baptist ended all prophecy', 'The law was abolished completely', 'a', 'Luke 16:16 — "The law and the prophets were until John: since that time the kingdom of God is preached, and every man presseth into it." This does not abolish the law (v.17) but marks a new epoch where the kingdom is actively offered.'),
('Luke', 16, 'adults', 7, 'What does Jesus mean by "it is easier for heaven and earth to pass, than one tittle of the law to fail"?', 'The law''s authority is permanent and inviolable — a "tittle" (keraia) is the smallest stroke distinguishing Hebrew letters, meaning even the most minute detail of God''s word will be fulfilled', 'The law is easily changed', 'Only major commandments matter', 'The law failed long ago', 'a', 'Luke 16:17 — "And it is easier for heaven and earth to pass, than one tittle of the law to fail." This affirms the enduring authority of Scripture even as the kingdom era dawns, preventing antinomian conclusions from verse 16.'),
('Luke', 16, 'adults', 8, 'What does the reversal of fortunes between the rich man and Lazarus teach about wealth and poverty?', 'Wealth without compassion leads to judgment while suffering endured in faith leads to comfort — Abraham says "thou in thy lifetime receivedst thy good things, and likewise Lazarus evil things: but now he is comforted, and thou art tormented." The reversal reflects Luke''s consistent theme of eschatological reversal', 'Poverty automatically guarantees heaven', 'Wealth automatically leads to hell', 'Economic status has no spiritual significance', 'a', 'Luke 16:25 — The reversal is not mechanical (rich=damned, poor=saved) but the rich man''s callous indifference to Lazarus at his gate (sins of omission) while having Moses and the prophets (v.29) reveals culpable disregard for both God''s word and God''s image-bearer.');

-- ═══ Luke Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 17, 'kids', 1, 'How many lepers did Jesus heal at once?', 'Ten lepers', 'Five lepers', 'Three lepers', 'Twenty lepers', 'a', 'Luke 17:12 — "And as he entered into a certain village, there met him ten men that were lepers, which stood afar off."'),
('Luke', 17, 'kids', 2, 'How many of the ten healed lepers came back to say thank you to Jesus?', 'Only one — and he was a Samaritan', 'All ten came back', 'Five came back', 'None of them came back', 'a', 'Luke 17:15-16 — "And one of them, when he saw that he was healed, turned back, and with a loud voice glorified God, And fell down on his face at his feet, giving him thanks: and he was a Samaritan."'),
('Luke', 17, 'kids', 3, 'What did Jesus say about faith as small as a mustard seed?', 'Even faith that small could tell a tree to be pulled up and planted in the sea, and it would obey', 'Mustard seed faith is too small to do anything', 'You need faith as big as a mountain', 'Only grown-ups can have real faith', 'a', 'Luke 17:6 — "If ye had faith as a grain of mustard seed, ye might say unto this sycamine tree, Be thou plucked up by the root, and be thou planted in the sea; and it should obey you."'),
-- Teens
('Luke', 17, 'teens', 1, 'What did Jesus say about those who cause little ones to stumble?', 'It were better for him that a millstone were hanged about his neck, and he cast into the sea, than that he should offend one of these little ones', 'Causing others to stumble is not a big deal', 'Only teachers can cause stumbling', 'God overlooks those who lead others astray', 'a', 'Luke 17:2 — "It were better for him that a millstone were hanged about his neck, and he cast into the sea, than that he should offend one of these little ones."'),
('Luke', 17, 'teens', 2, 'What question did Jesus ask about the nine lepers who did not return?', 'Were there not ten cleansed? but where are the nine? There are not found that returned to give glory to God, save this stranger', 'Jesus did not notice they were gone', 'Jesus said it was fine they did not return', 'Jesus sent the disciples to find them', 'a', 'Luke 17:17-18 — "And Jesus answering said, Were there not ten cleansed? but where are the nine? There are not found that returned to give glory to God, save this stranger."'),
('Luke', 17, 'teens', 3, 'What did Jesus say about the location of the kingdom of God?', 'The kingdom of God is within you — it does not come with outward observation', 'The kingdom of God is in Jerusalem only', 'The kingdom of God is in a faraway place', 'The kingdom of God is visible to everyone', 'a', 'Luke 17:20-21 — "The kingdom of God cometh not with observation: Neither shall they say, Lo here! or, lo there! for, behold, the kingdom of God is within you."'),
('Luke', 17, 'teens', 4, 'What Old Testament examples did Jesus use to describe the days of the Son of man?', 'The days of Noah (people eating and drinking until the flood came) and the days of Lot (people eating and drinking until fire fell on Sodom) — sudden destruction came upon the unprepared', 'The days of Moses and the Red Sea', 'The days of David and Solomon', 'The days of Elijah and Elisha', 'a', 'Luke 17:26-29 — "And as it was in the days of Noe, so shall it be also in the days of the Son of man... Likewise also as it was in the days of Lot... Even thus shall it be in the day when the Son of man is revealed."'),
('Luke', 17, 'teens', 5, 'What warning did Jesus give using the example of Lot''s wife?', 'Remember Lot''s wife — she looked back and was turned into a pillar of salt. Do not look back or cling to worldly things when the day of judgment comes', 'Lot''s wife was an example of faith', 'Looking back is perfectly safe', 'Lot''s wife was saved in the end', 'a', 'Luke 17:32 — "Remember Lot''s wife." The brief command recalls Genesis 19:26. She looked back (longing for what she left behind), becoming a warning against attachment to the world when God calls for decisive departure.'),
-- Adults
('Luke', 17, 'adults', 1, 'What does the account of the ten lepers and only one returning reveal about gratitude and faith?', 'Healing was given to all ten, but only the Samaritan (a social and religious outsider) returned to give glory to God — Jesus links his gratitude to saving faith: "thy faith hath made thee whole." The nine received physical healing but missed the deeper spiritual blessing', 'All ten lepers were equally grateful', 'Gratitude has no connection to faith', 'Only Jews could be truly grateful', 'a', 'Luke 17:19 — "Thy faith hath made thee whole." The word "whole" (sozo) can mean both healed and saved. The Samaritan received more than physical healing — his faith-fuelled gratitude brought spiritual wholeness.'),
('Luke', 17, 'adults', 2, 'What does "the kingdom of God is within you" (entos humon) mean, given that Jesus is speaking to Pharisees?', 'Most likely "the kingdom of God is in your midst/among you" — Jesus Himself, standing before them, is the presence of the kingdom. The kingdom is not coming with signs to be observed because the King is already there', 'Each Pharisee had the kingdom inside them', 'The kingdom was only a future event', 'The Pharisees were already in the kingdom', 'a', 'Luke 17:21 — "Entos humon" can mean "within you" or "in your midst." Since Jesus addresses hostile Pharisees, "among you" (in the person of Jesus) is the more likely reading. The kingdom is present in the King.'),
('Luke', 17, 'adults', 3, 'What does Jesus'' comparison with the days of Noah and Lot teach about the manner of His return?', 'Life will proceed with apparent normalcy (eating, drinking, marrying, buying, selling, building) right up to the moment of sudden, unexpected judgment — the warning is against complacency, not against daily activities themselves', 'Jesus will return only during wartime', 'Everyone will know the exact date', 'His return will be gradual and slow', 'a', 'Luke 17:26-30 — The point is not that eating and drinking are sinful, but that people will be absorbed in ordinary life, oblivious to impending judgment. Suddenness and surprise characterise both Noah''s flood, Sodom''s fire, and Christ''s return.'),
('Luke', 17, 'adults', 4, 'What does "whosoever shall seek to save his life shall lose it; and whosoever shall lose his life shall preserve it" teach about the day of Christ''s return?', 'When the Son of Man is revealed, those who cling to earthly possessions and security will perish, while those willing to abandon everything for Christ will be saved — it echoes 9:24 but applied specifically to eschatological judgment', 'This only applied to the first century', 'Physical survival should be the top priority', 'This teaching contradicts Luke 9:24', 'a', 'Luke 17:33 — Applied eschatologically, this means that attempts to preserve one''s life by compromising faith during the tribulation will result in eternal loss, while willingness to lose everything for Christ ensures eternal preservation.'),
('Luke', 17, 'adults', 5, 'What does the duty of the "unprofitable servant" teach about merit before God?', 'Even after doing everything commanded, believers should say "We are unprofitable servants: we have done that which was our duty to do" — obedience earns no surplus merit because God owes nothing to creatures who merely fulfil their obligations', 'Servants can earn extra credit with God', 'Perfect obedience makes God indebted to us', 'This only applies to paid workers', 'a', 'Luke 17:10 — "When ye shall have done all those things which are commanded you, say, We are unprofitable servants: we have done that which was our duty to do." This undercuts all self-congratulation and merit theology.'),
('Luke', 17, 'adults', 6, 'What does "one shall be taken, and the other shall be left" describe in context?', 'The sudden, discriminating nature of judgment at Christ''s return — two people in identical circumstances (same bed, same mill) will have different destinies, determined by their relationship to Christ, not their external situation', 'Physical rapture of believers', 'Random selection with no pattern', 'Taken refers to punishment, not rescue', 'a', 'Luke 17:34-35 — "Two men in one bed; the one shall be taken, and the other shall be left. Two women shall be grinding together; the one shall be taken, and the other left." The context of judgment (Noah, Lot) suggests separation between the saved and the lost.'),
('Luke', 17, 'adults', 7, 'What does Jesus'' instruction about forgiveness — "if he trespass against thee seven times in a day, and seven times in a day turn again to thee, saying, I repent; thou shalt forgive him" — demand?', 'Unlimited, repeated forgiveness whenever repentance is expressed — the number seven represents completeness, meaning there should be no cap on a believer''s willingness to forgive a repentant person', 'Forgiveness is optional after the third offence', 'You should only forgive once', 'Seven is the maximum number of times to forgive', 'a', 'Luke 17:4 — "And if he trespass against thee seven times in a day, and seven times in a day turn again to thee, saying, I repent; thou shalt forgive him." The seemingly impossible demand drove the disciples to cry: "Lord, increase our faith" (v.5).'),
('Luke', 17, 'adults', 8, 'What does Jesus mean by "Where the body is, thither will the eagles be gathered together"?', 'This proverbial saying means that judgment will be as unmistakable and as naturally drawn to its object as vultures to a carcass — there will be no need to search for the coming of the Son of Man, for it will be self-evident', 'Eagles will literally gather at Christ''s return', 'This refers to Roman military standards', 'The saying has no deeper meaning', 'a', 'Luke 17:37 — "Wheresoever the body is, thither will the eagles be gathered together." The proverb (cf. Job 39:30) answers the disciples'' question "Where, Lord?" — judgment will unerringly find its target, as birds of prey find carrion.');

-- ═══ Luke Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Luke', 18, 'kids', 1, 'What did Jesus say about children coming to Him?', 'Suffer little children to come unto me, and forbid them not: for of such is the kingdom of God', 'Children must wait until they are older', 'Only adults can come to Jesus', 'Children are not important to God', 'a', 'Luke 18:16 — "But Jesus called them unto him, and said, Suffer little children to come unto me, and forbid them not: for of such is the kingdom of God."'),
('Luke', 18, 'kids', 2, 'What prayer did the tax collector pray in the temple?', 'God be merciful to me a sinner', 'Thank you God that I am so good', 'God, look at all the good things I do', 'God, I am better than other people', 'a', 'Luke 18:13 — "And the publican, standing afar off, would not lift up so much as his eyes unto heaven, but smote upon his breast, saying, God be merciful to me a sinner."'),
('Luke', 18, 'kids', 3, 'What did the blind man near Jericho shout to Jesus?', 'Jesus, thou Son of David, have mercy on me!', 'Jesus, make me rich!', 'Jesus, give me food!', 'Jesus, take me to Jerusalem!', 'a', 'Luke 18:38 — "And he cried, saying, Jesus, thou Son of David, have mercy on me."'),
-- Teens
('Luke', 18, 'teens', 1, 'What is the lesson of the parable of the persistent widow?', 'Men ought always to pray, and not to faint — if an unjust judge answers persistent pleas, how much more will God answer His elect who cry to Him day and night', 'Prayer only works once', 'God is like the unjust judge', 'Only widows should pray persistently', 'a', 'Luke 18:1,7 — "That men ought always to pray, and not to faint... And shall not God avenge his own elect, which cry day and night unto him, though he bear long with them?"'),
('Luke', 18, 'teens', 2, 'What was wrong with the Pharisee''s prayer in the temple?', 'He thanked God that he was not like other men and boasted about his own righteousness — he was praying to himself, not truly to God', 'His prayer was a perfect example', 'He was too humble in his prayer', 'He prayed for everyone equally', 'a', 'Luke 18:11-12 — "The Pharisee stood and prayed thus with himself, God, I thank thee, that I am not as other men are, extortioners, unjust, adulterers, or even as this publican. I fast twice in the week, I give tithes of all that I possess."'),
('Luke', 18, 'teens', 3, 'Who went home justified — the Pharisee or the tax collector?', 'The tax collector — because he humbled himself before God, while the Pharisee exalted himself', 'The Pharisee, because he followed all the rules', 'Both went home justified equally', 'Neither one was justified', 'a', 'Luke 18:14 — "I tell you, this man went down to his house justified rather than the other: for every one that exalteth himself shall be abased; and he that humbleth himself shall be exalted."'),
('Luke', 18, 'teens', 4, 'What did the rich ruler lack even though he kept the commandments?', 'He needed to sell all that he had and distribute to the poor, and follow Jesus — he lacked willingness to put Jesus above his wealth', 'He lacked more money', 'He lacked political power', 'He lacked better education', 'a', 'Luke 18:22 — "Yet lackest thou one thing: sell all that thou hast, and distribute unto the poor, and thou shalt have treasure in heaven: and come, follow me."'),
('Luke', 18, 'teens', 5, 'What did Jesus say about a camel and a needle''s eye?', 'It is easier for a camel to go through a needle''s eye, than for a rich man to enter into the kingdom of God', 'Rich people always enter the kingdom easily', 'Camels can easily fit through small gates', 'Wealth is a sign of God''s guaranteed favour', 'a', 'Luke 18:25 — "For it is easier for a camel to go through a needle''s eye, than for a rich man to enter into the kingdom of God."'),
-- Adults
('Luke', 18, 'adults', 1, 'What does the parable of the unjust judge teach through a "how much more" (a fortiori) argument?', 'If an unjust judge who neither fears God nor regards man eventually grants justice because of persistent pleading, how much more will the perfectly just and loving God vindicate His elect who cry to Him — the contrast is between an unwilling judge and a willing Father', 'God is reluctant like the judge', 'Prayer is useless because God is unjust', 'Only persistent people deserve answers', 'a', 'Luke 18:6-8 — "Hear what the unjust judge saith. And shall not God avenge his own elect...? I tell you that he will avenge them speedily." The argument is from lesser to greater: if even a corrupt judge responds to persistence, God certainly will.'),
('Luke', 18, 'adults', 2, 'What makes the Pharisee''s prayer theologically deficient despite its outward religiosity?', 'He used prayer as self-congratulation before God, comparing himself to others rather than measuring himself against God''s standard — his prayer was essentially a testimony to himself ("prayed thus with himself"), not genuine communion with God', 'His prayer was doctrinally perfect', 'He was too generous in his praise', 'His fasting and tithing were wrong', 'a', 'Luke 18:11 — "The Pharisee stood and prayed thus with himself." The phrase "with himself" (pros heauton) is devastating — his prayer never reached God. He compared himself to the publican (downward comparison) instead of to God (upward comparison).'),
('Luke', 18, 'adults', 3, 'What does the publican''s prayer "God be merciful to me a sinner" reveal about justification?', 'The Greek "hilastheti" (be propitiated/merciful) is a sacrificial term — the publican appeals to God''s atoning mercy, not his own merit. He is justified because he recognised his utter need for divine grace, aligning with Paul''s theology of justification by faith', 'He was asking for something he had earned', 'His prayer was too short to be effective', 'He should have listed his good deeds too', 'a', 'Luke 18:13-14 — "Hilastheti moi to hamartolo" — literally "be propitiated toward me the sinner." The definite article "the sinner" shows he sees himself as the sinner, not merely one among many. His justification comes by grace through humble faith.'),
('Luke', 18, 'adults', 4, 'Why does Jesus respond "Why callest thou me good? none is good, save one, that is, God" to the rich ruler?', 'Jesus is not denying His divinity but forcing the ruler to think about the implications of his words — if only God is good, and Jesus is good, then the ruler must reckon with who Jesus truly is. It is a Socratic challenge, not a self-denial', 'Jesus was admitting He was not good', 'Jesus was confused about His own nature', 'Jesus was being falsely modest', 'a', 'Luke 18:19 — "Why callest thou me good? none is good, save one, that is, God." Rather than rejecting the title, Jesus challenges the ruler to think more deeply: either withdraw the word "good" or accept its divine implications.'),
('Luke', 18, 'adults', 5, 'What does the rich ruler''s response to Jesus'' command reveal about the nature of idolatry?', 'He was very sorrowful because he was very rich — his wealth had become his functional god. He kept the commandments outwardly but violated the first commandment ("no other gods before me") because money held the supreme place in his heart', 'He was simply too poor to give anything', 'He was planning to give later', 'He was the most righteous person Jesus met', 'a', 'Luke 18:23 — "He was very sorrowful: for he was very rich." His sorrow reveals the idol — what we cannot give up is what we worship. The one commandment the ruler could not keep exposed the one he had broken all along: "Thou shalt have no other gods before me."'),
('Luke', 18, 'adults', 6, 'What does "the things which are impossible with men are possible with God" mean in the context of the rich ruler?', 'Salvation is humanly impossible for anyone (not just the rich) — no one can save themselves. But God can do what humans cannot, including transforming hearts enslaved to wealth. This maintains both the impossibility of self-salvation and the sovereignty of divine grace', 'Only poor people can be saved', 'Wealth makes salvation easier', 'God forces people to be saved', 'a', 'Luke 18:27 — "The things which are impossible with men are possible with God." The disciples'' astonishment ("Who then can be saved?") shows they understood Jesus was not just talking about the rich — if even the "blessed" wealthy cannot enter, who can? Only God makes salvation possible.'),
('Luke', 18, 'adults', 7, 'What does Jesus'' third passion prediction (vv. 31-33) add to the previous ones?', 'This prediction is the most detailed — adding that He will be delivered to the Gentiles, mocked, spitefully entreated, spitted on, scourged, and killed, then rise the third day. Yet the disciples "understood none of these things" — the cross remained incomprehensible to them', 'This prediction was identical to the first', 'Jesus gave fewer details each time', 'The disciples fully understood this prediction', 'a', 'Luke 18:31-34 — The third prediction is the fullest (Gentile involvement, specific sufferings). Yet "they understood none of these things, and this saying was hid from them." The messianic secret extends to the disciples'' comprehension of the passion.'),
('Luke', 18, 'adults', 8, 'What is the significance of the blind man calling Jesus "Son of David" near Jericho?', 'It is a messianic title — the blind man had clearer spiritual sight than the seeing crowd who tried to silence him. His persistence and correct identification of Jesus as the Davidic Messiah were rewarded with both physical and spiritual healing', 'Son of David was a generic greeting', 'The blind man was simply guessing', 'This title had no messianic meaning', 'a', 'Luke 18:38-42 — "Jesus, thou Son of David, have mercy on me!" The irony is profound: a blind beggar "sees" what the religious leaders cannot — that Jesus is the promised Messiah from David''s line. His faith, expressed through persistence, made him whole.');
